@@ -0,0 +1,27 @@
+const path = require('path');
+
+/**
+ * Safely resolve a file path within a base directory.
+ * Throws an error if the resolved path is outside the base directory.
+ * @param {string} baseDir - The base directory to constrain the path to.
+ * @param {string} requestedPath - The requested file path.
+ * @returns {string} The normalized, secured absolute path.
+ */
+function safeResolvePath(baseDir, requestedPath) {
+  const normalizedBase = path.resolve(baseDir);
+  const normalizedRequested = path.resolve(requestedPath);
+
+  // Ensure the resolved path starts with the base directory
+  if (!normalizedRequested.startsWith(normalizedBase)) {
+    throw new Error(
+      `Path traversal attempt blocked: requested path "${requestedPath}" resolves outside base directory "${baseDir}"`
+    );
+  }
+
+  return normalizedRequested;
+}
+
+module.exports = {
+  safeResolvePath
+};

