+const crypto = require('crypto');
+
+/**
+ * Encrypt a cryptographic key using a password-derived key
+ * @param {string} key - The cryptographic key to encrypt
+ * @param {string} password - The password to use for encryption
+ * @returns {string} Encrypted key (IV:ciphertext:authTag)
+ */
+function encryptKey(key, password) {
+  const salt = crypto.randomBytes(16);
+  const keyMaterial = crypto.scryptSync(password, salt, 32);
+  const iv = crypto.randomBytes(12);
+  const cipher = crypto.createCipheriv('aes-256-gcm', keyMaterial, iv);
+  
+  let encrypted = cipher.update(key, 'utf8', 'hex');
+  encrypted += cipher.final('hex');
+  const authTag = cipher.getAuthTag();
+  
+  return `${iv.toString('hex')}:${encrypted}:${authTag.toString('hex')}:${salt.toString('hex')}`;
+}
+
+/**
+ * Decrypt a cryptographic key using a password-derived key
+ * @param {string} encryptedKey - The encrypted key (IV:ciphertext:authTag:salt)
+ * @param {string} password - The password to use for decryption
+ * @returns {string} Decrypted key
+ */
+function decryptKey(encryptedKey, password) {
+  const [ivHex, ciphertext, authTagHex, saltHex] = encryptedKey.split(':');
+  const iv = Buffer.from(ivHex, 'hex');
+  const authTag = Buffer.from(authTagHex, 'hex');
+  const salt = Buffer.from(saltHex, 'hex');
+  
+  const keyMaterial = crypto.scryptSync(password, salt, 32);
+  const decipher = crypto.createDecipheriv('aes-256-gcm', keyMaterial, iv);
+  decipher.setAuthTag(authTag);
+  
+  let decrypted = decipher.update(ciphertext, 'hex', 'utf8');
+  decrypted += decipher.final('utf8');
+  
+  return decrypted;
+}
+
+module.exports = { encryptKey, decryptKey };

