+/**
+ * Validate and sanitize timezone parameter to prevent code injection
+ * @param {string} timezone - The timezone string to validate
+ * @returns {string} - Sanitized timezone string
+ * @throws {Error} - If timezone contains invalid characters
+ */
+function validateTimezone(timezone) {
+  if (typeof timezone !== 'string') {
+    throw new Error('Timezone must be a string');
+  }
+
+  // Remove any null bytes
+  timezone = timezone.replace(/\0/g, '');
+
+  // Only allow safe timezone values
+  // Valid timezones are either:
+  // 1. 'local' or 'Z' (UTC)
+  // 2. IANA timezone names (letters, numbers, underscores, slashes, plus, minus)
+  // 3. MySQL timezone offset format: [+-]HH:MM
+  
+  const timezoneRegex = /^(?:local|Z|[A-Za-z_][A-Za-z0-9_\/+\-]+|[+-]\d{2}:\d{2})$/;
+  
+  if (!timezoneRegex.test(timezone)) {
+    throw new Error(`Invalid timezone format: ${timezone}`);
+  }
+
+  // Additional safety: ensure no SQL injection patterns
+  const dangerousPatterns = /[;'"`\\]|--|\/\*|\*\//;
+  if (dangerousPatterns.test(timezone)) {
+    throw new Error(`Invalid characters in timezone: ${timezone}`);
+  }
+
+  return timezone;
+}
+
+module.exports = { validateTimezone };

